```plantuml
@startuml
class Proyecto {
  Nombre: "1 Texto"
  Fecha de inicio: 1 Tiempo
  Fecha de fin: 0..1 Tiempo
}

class "Miembros del Equipo" as Miembros_del_Equipo {
  Nombre: 1 Texto
  Apellidos: 1 Texto
  Rol: 0..* Texto
}

class "Lugar de Actuacion" as Lugar_de_Actuacion {
  Nombre: 0..* Texto
  Coordenada X: 1 Número
  Coordenada Y: 1 Número
}

Proyecto -[hidden]right- Miembros_del_Equipo
Proyecto -[hidden]down- Lugar_de_Actuacion
@enduml
